#!/bin/sh
# Database credentials, replace with your actual values in a real environment
DBUSER="backup_user"  # Replace 'your-username' here if needed
PASSWORD="'BackupPass123'"   # Do not forget to encrypt this password or use an encrypted method for storing sensitive data. Also don’t hardcode the Password in your script, consider using a secure way of handling it like environment variables and/or configuration files ‘secure_password'
HOST="localhost"    # Replace 'your-hostname', if needed (default is localhost)  
DBNAME=$(mysql --user=${DBUSER} --password=$PASSWORD -h $HOST -e "SHOW DATABASES;" | tr -d '|\n' | grep -v Database)  # Get all database names and pipe them into a loop to select the one you want
for db in $DBNAME; do  
    if [[ $db != 'information_schema' ]] && [[ $db != '_Schema' ]]; then    
        echo "Creating dump for DB: $db"  # Prints out which database is being dumped to the console. Uncomment this line and change it as needed  
         mysqldump --force --user=${DBUSER} --password=$PASSWORD -h $HOST  $db > /path/to/backup/location/$db.sql  # Dumps DB into a file in specified location, replace '/path/to/your-directory' with your actual directory  
    fi    
done; unset db